SELECT faq.UFQ_NO AS ufq_no , faq.UFQ_QUESTION AS ufq_question , faq.UFQ_ANSWER AS ufq_answer , faq.UFQ_AM_USERID AS ufq_am_userid , DATE_FORMAT(faq.UFQ_REGDATE, '%Y-%m-%d %h:%i') AS ufq_regdate FROM TBL_ZONE_FAQ faq WHERE 1=1
AND ( faq.UFQ_QUESTION LIKE CONCAT('%', #{searchKey}, '%') OR faq.UFQ_ANSWER LIKE CONCAT('%', #{searchKey}, '%') )
ORDER BY faq.UFQ_REGDATE DESC LIMIT #{pagenum}, #{pageSize}

mapper.update:
UPDATE TBL_MEMBER_DEVICE
SET
	UMD_NAME = #{umd_name}
WHERE
	UMD_CODE = #{umd_code}
